#include <sstream>
#include <stdexcept>

// This driver assumes the solution's main function is renamed to `solution_main`
// for testing purposes to avoid symbol conflicts. The actual solution file
// should contain a `main` function.

extern int solution_main(); // Forward declaration for the solution's main

std::string run_solution(const std::string& input) {
    std::istringstream iss(input);
    std::ostringstream oss;

    // Redirect cin and cout
    std::streambuf* old_cin = std::cin.rdbuf(iss.rdbuf());
    std::streambuf* old_cout = std::cout.rdbuf(oss.rdbuf());

    try {
        solution_main(); // Call the solution's main function
    } catch (const std::exception& e) {
        oss << "Runtime Error: " << e.what();
    } catch (...) {
        oss << "Runtime Error: Unknown exception";
    }

    // Restore cin and cout
    std::cin.rdbuf(old_cin);
    std::cout.rdbuf(old_cout);

    return oss.str();
}

